SELECT 
  (SELECT COUNT(*) FROM public.employees WHERE organization_id = '9321e605-1b36-4b31-a8ef-4bf5c58b5542') as employees,
  (SELECT COUNT(*) FROM public.skills WHERE organization_id = '9321e605-1b36-4b31-a8ef-4bf5c58b5542') as skills,
  (SELECT COUNT(*) FROM public.employee_skills WHERE employee_id IN (SELECT id FROM public.employees WHERE organization_id = '9321e605-1b36-4b31-a8ef-4bf5c58b5542')) as employee_skills,
  (SELECT COUNT(*) FROM public.departments WHERE organization_id = '9321e605-1b36-4b31-a8ef-4bf5c58b5542') as departments,
  (SELECT COUNT(*) FROM public.teams WHERE organization_id = '9321e605-1b36-4b31-a8ef-4bf5c58b5542') as teams,
  (SELECT COUNT(*) FROM public.invoices WHERE organization_id = '9321e605-1b36-4b31-a8ef-4bf5c58b5542') as invoices,
  (SELECT COUNT(*) FROM public.expenses WHERE organization_id = '9321e605-1b36-4b31-a8ef-4bf5c58b5542') as expenses,
  (SELECT COUNT(*) FROM public.vendors WHERE organization_id = '9321e605-1b36-4b31-a8ef-4bf5c58b5542') as vendors,
  (SELECT COUNT(*) FROM public.subscriptions WHERE organization_id = '9321e605-1b36-4b31-a8ef-4bf5c58b5542') as subscriptions,
  (SELECT COUNT(*) FROM public.campaigns WHERE organization_id = '9321e605-1b36-4b31-a8ef-4bf5c58b5542') as campaigns,
  (SELECT COUNT(*) FROM public.documents WHERE organization_id = '9321e605-1b36-4b31-a8ef-4bf5c58b5542') as documents,
  (SELECT COUNT(*) FROM public.forecasts WHERE organization_id = '9321e605-1b36-4b31-a8ef-4bf5c58b5542') as forecasts,
  (SELECT COUNT(*) FROM public.workflows WHERE organization_id = '9321e605-1b36-4b31-a8ef-4bf5c58b5542') as workflows,
  (SELECT COUNT(*) FROM public.custom_fields WHERE organization_id = '9321e605-1b36-4b31-a8ef-4bf5c58b5542') as custom_fields,
  (SELECT COUNT(*) FROM public.sla_policies WHERE organization_id = '9321e605-1b36-4b31-a8ef-4bf5c58b5542') as sla_policies,
  (SELECT COUNT(*) FROM public.support_tickets WHERE organization_id = '9321e605-1b36-4b31-a8ef-4bf5c58b5542') as support_tickets,
  (SELECT COUNT(*) FROM public.time_entries WHERE organization_id = '9321e605-1b36-4b31-a8ef-4bf5c58b5542') as time_entries,
  (SELECT COUNT(*) FROM public.audit_logs WHERE organization_id = '9321e605-1b36-4b31-a8ef-4bf5c58b5542') as audit_logs,
  (SELECT COUNT(*) FROM public.api_keys WHERE organization_id = '9321e605-1b36-4b31-a8ef-4bf5c58b5542') as api_keys,
  (SELECT COUNT(*) FROM public.webhooks WHERE organization_id = '9321e605-1b36-4b31-a8ef-4bf5c58b5542') as webhooks;